print('=== junction analysis ===')
# egfp core: how much of egfp is in output
def longest_prefix(s, out):
    for L in range(len(s),0,-1):
        if s[:L] in out: return L, out.find(s[:L])
    return 0,-1
def longest_suffix(s,out):
    for L in range(len(s),0,-1):
        if s[-L:] in out: return L, out.find(s[-L:])
    return 0,-1
for nm,s in [('egfp',egfp),('flag',flag),('snap',snap)]:
    print(nm,'len',len(s))
    print('  full prefix in out:',longest_prefix(s,out))
    print('  full suffix in out:',longest_suffix(s,out))
